x_424426_devops_context_menu_item.client_script:
(() => {

	const bc = new BroadcastChannel('x_424426_devops');
	bc.postMessage({
		type: 'openInStudio',
		sys_id: g_form.getUniqueValue(),
		table: g_form.getTableName()
	});
	bc.close();

})();

x_424426_devops_context_menu_item.condition_script:
(() => {
	var env = window.top.location.pathname;
	var devEnv = (typeof isDevStudio != 'undefined' && !!isDevStudio)
		|| (typeof devStudioAPI != 'undefined' && !!devStudioAPI)
		|| env?.startsWith('/$studio.do')
		|| env?.startsWith('/now/servicenow-studio');

	if (devEnv && !window.top.x_424426_devops_listener) {
		window.top.x_424426_devops_listener = new BroadcastChannel('x_424426_devops');
		window.top.x_424426_devops_listener.onmessage = function (event) {
			if (event.data.type == 'openInStudio') {
				devStudioAPI.openStudioTab(event.data.table + '.do?sys_id=' + event.data.sys_id);
			} else if (event.data.type == 'isStudioOpen') {
				window.top.x_424426_devops_listener.postMessage({
					type: 'studio',
					studio: env
				});
			}
		};
	}

	if (!devEnv) {
		// only show item if not in dev environment and if a studio is open
		const bc = new BroadcastChannel('x_424426_devops');
		const studioOpen = new Promise(resolve => {
			bc.onmessage = function (event) {
				if (event.data.type == 'studio') {
					resolve('studio');
				}
			};

			bc.postMessage({
				type: 'isStudioOpen'
			});
		});

		return Promise
			.race([studioOpen, new Promise(resolve => setTimeout(resolve, 100))])
			.then(value => {
				bc.close();
				return !!value;
			});
	}

	return false;
})();
